// Controlador de Drone FPV (Modo Assistido / Fácil) com Som Dinâmico

const SPEED_FORWARD = 15;
const SPEED_STRAFE = 12;
const SPEED_VERTICAL = 8;
const YAW_SPEED = 2.5;
const MOUSE_SENSITIVITY = 0.002;

// Parâmetros públicos editáveis no editor para assistência do mouse
export const MOUSE_STEERING_ENABLED = true; 
export const MOUSE_STEERING_SENSITIVITY = 1.2; 
export const MOUSE_AUTO_CENTER = 3.5; 

// Arrasto para parar suavemente quando soltar as teclas
const LINEAR_DRAG = 0.90; 

// Intensidade da inclinação visual (tilt) ao mover
const TILT_MAX = 0.35; // radianos

// Variáveis para o controle dinâmico do som do motor (ECS)
let currentPitchFactor = 1.0;
let mousePitchInput = 0;
let mouseYawInput = 0;

// Sistema de projéteis e vida
let droneHealth = 100;
let activeProjectiles = [];
let lastShootTime = 0;
const SHOOT_COOLDOWN = 0.2; // 200ms entre tiros

export function onAwake() {
    // Inicialização da Telemetria Global para o HUD Visor
    if (typeof window !== 'undefined') {
        window.droneTelemetry = { altitude: "0.0", speed: "0.0", health: "100" };

        // Limpa projéteis órfãos de sessões de teste anteriores do editor
        if (window._activeDroneProjectiles) {
            window._activeDroneProjectiles.forEach(p => {
                if (p.mesh && p.mesh.parent) {
                    p.mesh.parent.remove(p.mesh);
                }
            });
        }
        window._activeDroneProjectiles = [];
        activeProjectiles = window._activeDroneProjectiles;

        // Registro robusto de eventos de rede limpando closures anteriores (HMR do Editor)
        if (window._handleRemoteShoot) {
            window.removeEventListener('network-packet-drone-shoot', window._handleRemoteShoot);
        }
        if (window._handleRemoteDamage) {
            window.removeEventListener('network-packet-drone-damage', window._handleRemoteDamage);
        }

        window._handleRemoteShoot = handleRemoteShoot;
        window._handleRemoteDamage = handleRemoteDamage;

        window.addEventListener('network-packet-drone-shoot', window._handleRemoteShoot);
        window.addEventListener('network-packet-drone-damage', window._handleRemoteDamage);
    }
}

export function onUpdate(delta) {
    const _THREE = typeof THREE !== 'undefined' ? THREE : (typeof engine !== 'undefined' && engine.THREE ? engine.THREE : null);
    if (!rigidBody || !_THREE) return;

    let moveZ = 0; // Frente/Trás
    let moveX = 0; // Esquerda/Direita
    let moveY = 0; // Subir/Descer
    let yaw = 0;   // Girar

    // === CONTROLES ASSISTIDOS (Mova-se como em um jogo FPS) ===

    // Subir / Descer
    if (Input.getKey("Space") || Input.getGamepadButton("R2")) moveY = 1;
    if (Input.getKey("ShiftLeft") || Input.getGamepadButton("L2")) moveY = -1;

    // Frente / Trás (Eixo Z no espaço local)
    if (Input.getKey("KeyW")) moveZ = -1; // -Z é para frente
    if (Input.getKey("KeyS")) moveZ = 1;  // +Z é para trás

    // Esquerda / Direita (Strafe no eixo X)
    if (Input.getKey("KeyA")) moveX = -1;
    if (Input.getKey("KeyD")) moveX = 1;

    // Girar (Yaw)
    if (Input.getKey("KeyQ")) yaw = 1;
    if (Input.getKey("KeyE")) yaw = -1;

    // Analógicos Gamepad
    const leftAxisX = Input.getGamepadAxis(0);
    const rightAxisY = Input.getGamepadAxis(3); 
    const rightAxisX = Input.getGamepadAxis(2);

    if (Math.abs(rightAxisY) > 0.1) moveZ = rightAxisY;
    if (Math.abs(rightAxisX) > 0.1) moveX = rightAxisX;
    if (Math.abs(leftAxisX) > 0.1) yaw = -leftAxisX;

    // Solicita Pointer Lock ao clicar com o botão esquerdo para habilitar deltas de mouse
    if (Input.getMouseButton && Input.getMouseButton(0) && Input.lockMouse) {
        Input.lockMouse();
    }

    if (typeof MOUSE_STEERING_ENABLED !== 'undefined' && MOUSE_STEERING_ENABLED) {
        const mouseDeltaX = Input.mouse ? Input.mouse.movementX : 0;
        const mouseDeltaY = Input.mouse ? Input.mouse.movementY : 0;

        // Sensibilidade reduzida para movimento do mouse para baixo (movementY > 0)
        const pitchSensitivity = mouseDeltaY > 0 ? 0.4 : 1.0;

        // Acumula os movimentos para o joystick virtual
        mouseYawInput -= mouseDeltaX * MOUSE_SENSITIVITY * MOUSE_STEERING_SENSITIVITY * 15;
        mousePitchInput += mouseDeltaY * MOUSE_SENSITIVITY * MOUSE_STEERING_SENSITIVITY * 15 * pitchSensitivity;

        // Limitadores do joystick virtual (-1.0 a 1.0)
        mouseYawInput = Math.max(-1.0, Math.min(1.0, mouseYawInput));
        mousePitchInput = Math.max(-1.0, Math.min(1.0, mousePitchInput));

        // Centralização automática suave se o mouse não estiver se movendo
        if (mouseDeltaX === 0) {
            mouseYawInput += (0 - mouseYawInput) * MOUSE_AUTO_CENTER * delta;
        }
        if (mouseDeltaY === 0) {
            mousePitchInput += (0 - mousePitchInput) * MOUSE_AUTO_CENTER * delta;
        }

        // Aplica o joystick do mouse nos inputs
        yaw += mouseYawInput;
        moveZ += mousePitchInput;
    }

    // === FÍSICA ASSISTIDA E AUTO-HOVER ===
    const currentVel = rigidBody.linvel();
    const rot = rigidBody.rotation();
    const q = new _THREE.Quaternion(rot.x, rot.y, rot.z, rot.w);

    // Pegar direção baseado APENAS na rotação YAW para não ir pro chão quando olhar pra baixo
    const euler = new _THREE.Euler().setFromQuaternion(q, 'YXZ');
    const yawQuat = new _THREE.Quaternion().setFromEuler(new _THREE.Euler(0, euler.y, 0));

    const forward = new _THREE.Vector3(0, 0, 1).applyQuaternion(yawQuat);
    const right = new _THREE.Vector3(1, 0, 0).applyQuaternion(yawQuat);

    // Define o arrasto dinâmico: menor ao pilotar (preserva momentum/derrapa), maior ao soltar controles (estabiliza)
    const hasInput = (moveZ !== 0 || moveX !== 0 || yaw !== 0);
    const currentDrag = hasInput ? 0.97 : LINEAR_DRAG;

    // Calcular nova velocidade linear no plano XZ
    let newVx = currentVel.x * currentDrag;
    let newVz = currentVel.z * currentDrag;

    newVx += (forward.x * moveZ * SPEED_FORWARD + right.x * moveX * SPEED_STRAFE) * delta * 5;
    newVz += (forward.z * moveZ * SPEED_FORWARD + right.z * moveX * SPEED_STRAFE) * delta * 5;

    // Movimento Vertical (Auto-Hover substitui gravidade)
    let newVy = 0;
    if (moveY !== 0) {
       newVy = moveY * SPEED_VERTICAL;
    } else {
       newVy = 0; // Trava no ar perfeitamente (Assisted Hover)
    }

    rigidBody.setLinvel({ x: newVx, y: newVy, z: newVz }, true);

    // === ROTAÇÃO ASSISTIDA E INCLINAÇÃO VISUAL (TILT) ===
    // Calcula inclinação alvo para dar a sensação visual de que o drone está se movendo
    const targetPitch = moveZ * TILT_MAX; 
    const targetRoll = -moveX * TILT_MAX; 

    euler.y += yaw * YAW_SPEED * delta; // Gira pra esquerda/direita livremente

    // Interpola suavemente para não dar solavanco
    euler.x += (targetPitch - euler.x) * 0.1;
    euler.z += (targetRoll - euler.z) * 0.1;

    const newQuat = new _THREE.Quaternion().setFromEuler(euler, 'YXZ');
    rigidBody.setRotation({ x: newQuat.x, y: newQuat.y, z: newQuat.z, w: newQuat.w }, true);

    // Zera a física angular, já que controlamos a rotação cinemáticamente
    rigidBody.setAngvel({x: 0, y: 0, z: 0}, true); 

    // === SISTEMA DE DISPARO DE PROJÉTEIS (TIRO) ===
    const now = performance.now();
    const canShoot = (now - lastShootTime) > (SHOOT_COOLDOWN * 1000);

    // Atira com clique do botão esquerdo (quando o pointer lock está ativo) ou com a tecla "KeyF" ou gatilho direito do gamepad
    const isPointerLocked = typeof document !== 'undefined' && document.pointerLockElement !== null;
    const clickToShoot = Input.getMouseButton && Input.getMouseButton(0) && isPointerLocked;
    const keyToShoot = Input.getKey && (Input.getKey("KeyF") || Input.getKey("Enter"));
    const gamepadShoot = Input.getGamepadButton && (Input.getGamepadButton("R1") || Input.getGamepadButton("FaceButtonDown"));

    if ((clickToShoot || keyToShoot || gamepadShoot) && canShoot) {
        lastShootTime = now;

        const currentTranslation = rigidBody.translation();
        const startPos = new _THREE.Vector3(currentTranslation.x, currentTranslation.y, currentTranslation.z);

        // Direção de disparo baseada na orientação atual do drone
        const rot = rigidBody.rotation();
        const q = new _THREE.Quaternion(rot.x, rot.y, rot.z, rot.w);
        const shootDirection = new _THREE.Vector3(0, 0, -1).applyQuaternion(q).normalize(); // -Z local é para frente

        // Ponto de partida do tiro um pouco à frente do drone para evitar autocolisão
        startPos.add(shootDirection.clone().multiplyScalar(1.2));

        const projId = 'proj-' + Math.floor(Math.random() * 100000);
        const ownerId = engine.network.getPlayerId();

        // Instancia localmente
        spawnProjectile(startPos, shootDirection, ownerId, projId);

        // Propaga para os outros no multiplayer
        if (engine.network.isConnected()) {
            engine.network.send({
                type: 'drone-shoot',
                projectileId: projId,
                ownerId: ownerId,
                position: [startPos.x, startPos.y, startPos.z],
                direction: [shootDirection.x, shootDirection.y, shootDirection.z]
            });
        }
    }

    // === ATUALIZAÇÃO DOS PROJÉTEIS E COLISÕES ===
    for (let i = activeProjectiles.length - 1; i >= 0; i--) {
        const proj = activeProjectiles[i];
        proj.lifeTime -= delta;

        if (proj.lifeTime <= 0) {
            if (proj.mesh && proj.mesh.parent) {
                proj.mesh.parent.remove(proj.mesh);
            }
            activeProjectiles.splice(i, 1);
            continue;
        }

        const moveDist = proj.speed * delta;
        const moveVec = proj.direction.clone().multiplyScalar(moveDist);
        proj.mesh.position.add(moveVec);

        // Apenas o dono da bala calcula a colisão no seu cliente
        if (proj.ownerId === engine.network.getPlayerId()) {
            const ghosts = engine.findAllByTag('multiplayer-ghost');
            let collided = false;

            for (const ghost of ghosts) {
                if (!ghost.active) continue;
                const ghostPos = engine.getPosition(ghost.id);
                if (!ghostPos) continue;

                const ghostVec = new _THREE.Vector3(ghostPos[0], ghostPos[1], ghostPos[2]);
                const dist = proj.mesh.position.distanceTo(ghostVec);

                if (dist < 1.8) { // Raio de colisão com o drone inimigo
                    collided = true;
                    const targetPlayerId = ghost.id.replace('ghost-', '');

                    console.log(`[Tiro] Acertamos o oponente ${targetPlayerId}!`);

                    // Envia pacote de dano pela rede
                    if (engine.network.isConnected()) {
                        engine.network.send({
                            type: 'drone-damage',
                            targetId: targetPlayerId,
                            damage: proj.damage,
                            attackerId: engine.network.getPlayerId()
                        });
                    }
                    break;
                }
            }

            if (collided) {
                if (proj.mesh && proj.mesh.parent) {
                    proj.mesh.parent.remove(proj.mesh);
                }
                activeProjectiles.splice(i, 1);
                continue;
            }
        }
    }

    // === ATUALIZAR VARIÁVEL DE TELEMETRIA GLOBAL E SOM ===
    if (typeof window !== 'undefined' && typeof Math !== 'undefined') {
        const altitude = rigidBody.translation().y.toFixed(1);
        const speedVal = Math.sqrt(newVx*newVx + newVy*newVy + newVz*newVz);
        const speed = speedVal.toFixed(1);
        window.droneTelemetry = { altitude, speed, health: droneHealth.toFixed(0) };

        // Atualiza áudio (pitch e volume) dinamicamente no componente ECS
        updateDroneAudio(moveX, moveY, moveZ, yaw, speedVal);
    }
}

function updateDroneAudio(moveX, moveY, moveZ, yaw, currentSpeed) {
    // Mede a atividade de input
    let inputIntensity = 0;
    if (moveX !== 0 || moveZ !== 0 || yaw !== 0) {
        inputIntensity = 0.5;
    }
    if (moveY !== 0) {
        inputIntensity = moveY > 0 ? 0.9 : 0.3; // Mais esforço ao subir, menos ao descer
    }

    // Combina o input do jogador com a velocidade atual do drone
    const speedRatio = Math.min(currentSpeed / SPEED_FORWARD, 1.0);
    const effort = Math.max(inputIntensity, speedRatio);

    // Fator de pitch do motor: 1.0 (idle) a 2.5 (RPM máximo)
    const targetPitch = 1.0 + effort * 1.5;
    currentPitchFactor += (targetPitch - currentPitchFactor) * 0.15; // Interpolação suave

    // Atualiza o componente Audio do ECS (para reproduzir via Three.js e propagar no multiplayer)
    if (typeof entity !== 'undefined' && entity && entity.components && entity.components.Audio && typeof updateComponent === 'function') {
        const audioVolume = 0.1 + effort * 0.4;
        updateComponent(entity.id, 'Audio', {
            playbackRate: currentPitchFactor,
            volume: audioVolume
        });
    }
}

// === AUXILIARES DO SISTEMA DE COMBATE E TIRO ===

function spawnProjectile(position, direction, ownerId, projectileId) {
    const _THREE = typeof THREE !== 'undefined' ? THREE : (typeof engine !== 'undefined' && engine.THREE ? engine.THREE : null);
    if (!threeCamera || !_THREE) return;

    // Encontra a cena 3D principal a partir da camera do Three.js
    let scene3D = threeCamera.parent;
    while (scene3D && scene3D.type !== "Scene") {
        scene3D = scene3D.parent;
    }
    if (!scene3D) return;

    // Pequeno cilindro azul orientado horizontalmente (no eixo Z)
    const geometry = new _THREE.CylinderGeometry(0.04, 0.04, 0.5, 8);
    geometry.rotateX(Math.PI / 2); // Alinha o cilindro com a direção Z de movimento

    // Material azul brilhante com emissividade
    const material = new _THREE.MeshBasicMaterial({
        color: 0x00a8ff,
        transparent: true,
        opacity: 0.95
    });

    const mesh = new _THREE.Mesh(geometry, material);
    mesh.position.copy(position);

    // Aponta o projétil na direção correta
    const targetPos = new _THREE.Vector3().copy(position).add(direction);
    mesh.lookAt(targetPos);

    scene3D.add(mesh);

    activeProjectiles.push({
        id: projectileId,
        ownerId: ownerId,
        mesh: mesh,
        direction: direction.clone().normalize(),
        speed: 90, // Alta velocidade para ser responsivo
        lifeTime: 2.0, // Remove após 2 segundos
        damage: 10
    });
}

function handleRemoteShoot(event) {
    const packet = event.detail;
    if (packet.ownerId === engine.network.getPlayerId()) return;

    const _THREE = typeof THREE !== 'undefined' ? THREE : (typeof engine !== 'undefined' && engine.THREE ? engine.THREE : null);
    if (!_THREE) return;

    // Instancia o projétil azul do oponente
    spawnProjectile(
        new _THREE.Vector3().fromArray(packet.position),
        new _THREE.Vector3().fromArray(packet.direction),
        packet.ownerId,
        packet.projectileId
    );
}

function handleRemoteDamage(event) {
    const packet = event.detail;
    if (packet.targetId === engine.network.getPlayerId()) {
        // Nós fomos atingidos!
        droneHealth = Math.max(0, droneHealth - packet.damage);
        console.log(`[Combate] Fomos atingidos por ${packet.attackerId}! Vida restante: ${droneHealth}`);

        // Se a vida for a zero, realiza o respawn
        if (droneHealth <= 0) {
            respawnDrone();
        }
    }
}

function respawnDrone() {
    droneHealth = 100;
    if (rigidBody) {
        // Teleporta para a posição de início no ar
        rigidBody.setTranslation({ x: 0, y: 10, z: 0 }, true);
        rigidBody.setLinvel({ x: 0, y: 0, z: 0 }, true);
        console.log("[Combate] Nosso drone caiu! Respawning no ar...");
    }
}

// Script do Visor HUD 3D (Simulador FPV)

export function onAwake() {
    console.log("[HUD Visor] Iniciado no simulador de drone");
}

export function onUpdate(delta) {
    // Obtém o canvas HTML5 interno da entidade "HUD Visor"
    const canvas = entity.HUDCanvas;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    // 1. Desenhar Retícula (Mira)
    ctx.strokeStyle = 'rgba(0, 255, 204, 0.9)';
    ctx.lineWidth = 3;

    ctx.beginPath();
    ctx.arc(cx, cy, 15, 0, Math.PI * 2);
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(cx - 30, cy); ctx.lineTo(cx - 10, cy);
    ctx.moveTo(cx + 10, cy); ctx.lineTo(cx + 30, cy);
    ctx.moveTo(cx, cy - 30); ctx.lineTo(cx, cy - 10);
    ctx.moveTo(cx, cy + 10); ctx.lineTo(cx, cy + 30);
    ctx.stroke();

    // 2. Desenhar Painel de Telemetria (Lado Esquerdo)
    ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
    ctx.fillRect(20, cy - 100, 350, 200);

    ctx.fillStyle = 'rgba(0, 255, 204, 1)';
    ctx.font = 'bold 24px monospace';
    ctx.fillText("MODO ASSISTIDO", 40, cy - 60);

    ctx.font = '18px monospace';
    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.fillText("[Espaço/Shift]: Subir/Descer", 40, cy - 20);
    ctx.fillText("[W/S/A/D]: Voar no plano", 40, cy + 10);
    ctx.fillText("[Q/E]: Girar Câmera", 40, cy + 40);

    // Obter dados do DroneController
    const tele = window.droneTelemetry || { altitude: "0.0", speed: "0.0" };

    ctx.font = 'bold 26px monospace';
    ctx.fillStyle = 'rgba(0, 255, 204, 1)';
    ctx.fillText("ALT: " + tele.altitude + "m", 40, cy + 80);

    // Telemetria Lateral Direita
    ctx.fillStyle = 'rgba(0, 0, 0, 0.4)';
    ctx.fillRect(canvas.width - 320, cy - 100, 300, 200);

    ctx.fillStyle = 'rgba(0, 255, 204, 1)';
    ctx.fillText("VELOCIDADE", canvas.width - 290, cy - 40);
    ctx.font = 'bold 42px monospace';
    ctx.fillText(tele.speed, canvas.width - 290, cy + 20);
    ctx.font = 'bold 20px monospace';
    ctx.fillText("km/h", canvas.width - 290, cy + 50);

    // Solicita que a engine atualize a textura da malha 3D na GPU
    entity.updateHUDTexture();
}
